const event = $json.body ?? $json;
const clean = (value, max) => String(value ?? '').replace(/[\u0000-\u001f\u007f]/g, ' ').replace(/\s+/g, ' ').trim().slice(0, max);
const type = clean(event.type, 64);
const data = event.data && typeof event.data === 'object' ? event.data : {};
const conversationId = clean(data.conversation_id, 128);
const agentId = clean(data.agent_id, 128);
const eventTimestamp = clean(event.event_timestamp, 32);
const supported = type === 'post_call_transcription' || type === 'call_initiation_failure';
const signatureVerifiedUpstream = String($json.headers?.['x-reference-signature-verified'] ?? '').toLowerCase() === 'true';
const valid = Boolean(conversationId && eventTimestamp);
const stableKey = valid ? `elevenlabs:${type}:${conversationId}` : '';
const record = { eventType: type, conversationId, agentId, eventTimestamp, status: clean(data.status, 32), callSuccessful: data.analysis?.call_successful === true, failureReason: clean(data.failure_reason, 120), idempotencyKey: stableKey };
const reason = !signatureVerifiedUpstream ? 'HMAC must be verified by a trusted upstream handler' : !supported ? 'Unsupported event type' : !valid ? 'conversation_id and event_timestamp are required' : '';
return [{ json: { readyForQueue: signatureVerifiedUpstream && supported && valid, rawPayloadStored: false, record, reason, note: 'Reference only: connect the ready branch to a durable queue after upstream HMAC verification' } }];
